package main

import (
	"log"
	"net/http"
	"time"

	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
	"github.com/prometheus/client_golang/prometheus/promhttp"
)

var (
	requestCounter = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "http_requests_total",
			Help: "Total number of HTTP requests",
		},
		[]string{"user_id", "endpoint", "method", "status_code"},
	)

	requestDuration = promauto.NewHistogramVec(
		prometheus.HistogramOpts{
			Name:    "http_request_duration_seconds",
			Help:    "HTTP request duration in seconds",
			Buckets: prometheus.DefBuckets,
		},
		[]string{"user_id", "endpoint", "method", "status_code"},
	)

	activeRequests = promauto.NewGaugeVec(
		prometheus.GaugeOpts{
			Name: "http_active_requests",
			Help: "Number of active HTTP requests",
		},
		[]string{"user_id", "endpoint", "method"},
	)

	userRequestCount = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "user_requests_total",
			Help: "Total number of requests per user",
		},
		[]string{"user_id"},
	)

	endpointRequestCount = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "endpoint_requests_total",
			Help: "Total number of requests per endpoint",
		},
		[]string{"endpoint"},
	)
)

func main() {
	http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
		userID := r.URL.Query().Get("user_id")
		if userID == "" {
			userID = "anonymous"
		}
		
		endpoint := r.URL.Path
		method := r.Method
		
		// Increment active requests
		activeRequests.WithLabelValues(userID, endpoint, method).Inc()
		userRequestCount.WithLabelValues(userID).Inc()
		endpointRequestCount.WithLabelValues(endpoint).Inc()
		
		// Record request start time
		start := time.Now()
		
		// Simulate some work
		time.Sleep(time.Millisecond * 100)
		
		// Calculate duration
		duration := time.Since(start).Seconds()
		
		// Simulate different status codes
		statusCode := 200
		if userID == "error_user" {
			statusCode = 500
		}
		
		// Record metrics
		requestCounter.WithLabelValues(userID, endpoint, method, string(rune(statusCode))).Inc()
		requestDuration.WithLabelValues(userID, endpoint, method, string(rune(statusCode))).Observe(duration)
		
		// Decrement active requests
		activeRequests.WithLabelValues(userID, endpoint, method).Dec()
		
		w.WriteHeader(statusCode)
		w.Write([]byte("Hello World"))
	})
	
	http.Handle("/metrics", promhttp.Handler())
	
	log.Println("Starting server on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}